def _norm_org(org):
    return 'AOI' if str(org or '').upper().startswith('AOI') else 'SBS'

def _expand_alias(value, org='SBS'):
    if isinstance(value, dict):
        return list(value.get(_norm_org(org), []))
    return list(value or [])

def coa_alias_candidates(code, org='SBS'):
    code = str(code or '').strip()
    out = []
    if code in LEGACY_TO_UCC_ALIAS:
        out.extend(_expand_alias(LEGACY_TO_UCC_ALIAS.get(code), org))
    out.append(code)
    if code == '1001':
        out.extend(['1020','1000'])
    seen = set(); clean = []
    for x in out:
        x = str(x or '').strip()
        if x and x not in seen:
            seen.add(x); clean.append(x)
    return clean

def seed_ucc_chart_of_accounts(cursor, org='SBS'):
    org = _norm_org(org)
    accounts = list(UCC_CHART_OF_ACCOUNTS)
    if org == 'AOI':
        accounts.extend(AOI_COA_EXTENSIONS)
    for code, name, category, sub_category, account_type, vat_applicable, currency in accounts:
        cursor.execute("""INSERT OR IGNORE INTO chart_of_accounts
            (id, code, account_name, category, sub_category, account_type, vat_applicable)
            VALUES (?,?,?,?,?,?,?)""",
            (str(uuid.uuid4()), str(code), name, category, sub_category, account_type, int(vat_applicable or 0)))

def ucc_coa_status(conn, org='SBS'):
    org = _norm_org(org)
    expected = len(UCC_CHART_OF_ACCOUNTS) + (len(AOI_COA_EXTENSIONS) if org == 'AOI' else 0)
    rows = conn.execute('SELECT code FROM chart_of_accounts').fetchall()
    present = {str(r[0]) for r in rows}
    official = {str(r[0]) for r in UCC_CHART_OF_ACCOUNTS}
    if org == 'AOI': official |= {str(r[0]) for r in AOI_COA_EXTENSIONS}
    installed = len(official & present)
    legacy_short = len([c for c in present if c.isdigit() and len(c) <= 4])
    return {
        'ok': True, 'org': org, 'official_expected': expected,
        'official_installed': installed, 'official_missing': max(0, expected - installed),
        'legacy_short_codes_present': legacy_short,
        'mode': 'Official UCC COA with ERP compatibility aliases',
        'bank_default_aliases': coa_alias_candidates('1001', org),
        'wht_aliases': coa_alias_candidates('2030', org),
        'whvat_aliases': coa_alias_candidates('2031', org),
        'ucf_aliases': coa_alias_candidates('2033', org),
    }
